import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { Plane, TrainFront, Bus } from "lucide-react";
import PlannerShell from "../components/PlannerShell";
import ProgressBar from "../components/ProgressBar";
import { StepLayout } from "../components/ui/StepLayout";
import { StepHero } from "../components/ui/StepHero";
import { OptionCard } from "../components/ui/OptionCard";
import { STEP_IMAGES } from "../components/ui/stepImages";

const options = [
  { icon: "✈️", bg: true, name: "Flight", chip: "Best value", sub: "IndiGo · 6E-234 · 2h 40m", price: "₹3,200", dur: "Non-stop", CardIcon: Plane },
  { icon: "✈️", bg: false, name: "Flight", sub: "Air India · AI-891 · 3h 10m", price: "₹4,100", dur: "1 stop", CardIcon: Plane },
  { icon: "🚂", bg: false, name: "Train", sub: "Himachal Exp · 2 days", price: "₹1,400", dur: "Sleeper AC", CardIcon: TrainFront },
  { icon: "🚌", bg: false, name: "Bus", sub: "HRTC Volvo · 36h", price: "₹900", dur: "Overnight", CardIcon: Bus },
];

const Travel = () => {
  const [selected, setSelected] = useState(0);
  const navigate = useNavigate();
  return (
    <PlannerShell
      mobileHeaderLeft={<span className="back-link" onClick={() => navigate("/mode-select")}>← Back</span>}
      mobileHeaderRight={<span className="header-action" onClick={() => navigate("/plan")}>Skip all</span>}
      footer={(
        <div className="sticky-bottom md:flex md:flex-col md:items-center md:gap-4 md:pt-2">
          <div className="flex w-full max-w-md flex-col items-stretch gap-3 md:mt-6 md:flex-row md:justify-center">
            <button
              type="button"
              className="cta-btn h-11 rounded-lg bg-blue-600 px-5 font-medium text-white transition-all hover:bg-blue-700 active:scale-[0.99] md:max-w-xs md:flex-1"
              onClick={() => navigate("/stay")}
            >
              Confirm transport →
            </button>
          </div>
          <div className="skip-link text-center" onClick={() => navigate("/stay")}>Skip this step</div>
        </div>
      )}
    >
      <StepLayout className="planner-container--travel planner-stack">
        <ProgressBar activeStep={0} />

        <StepHero
          stepLabel="Step 2 of 5"
          title="How will you travel?"
          subtitle="Kolkata → Manali · Outbound journey"
          imageSrc={STEP_IMAGES.travel}
          imageAlt="Tropical beach and ocean"
        />

        <div className="planner-travel-options md:hidden">
          <div className="planner-section-label">Recommended for you</div>
          {options.map((o, i) => (
            <div key={i}>
              {i === 1 && <div className="planner-section-label mt-4">Other options</div>}
              <div
                className={`planner-opt-with-badge d-opt-card${selected === i ? " d-opt-card--selected" : ""}${i === 0 ? " d-opt-card--rec" : ""}`}
                onClick={() => setSelected(i)}
              >
                {i === 0 && <span className="planner-corner-badge">Recommended</span>}
                <div className={`travel-opt-icon${o.bg ? " blue-bg" : ""}`}>{o.icon}</div>
                <div className="travel-opt-info">
                  <div className="travel-opt-name">
                    {o.name}
                    {o.chip && <span className="rec-chip">{o.chip}</span>}
                  </div>
                  <div className="travel-opt-sub">{o.sub}</div>
                </div>
                <div className="d-opt-price-col">
                  <div className="travel-opt-price">{o.price}</div>
                  <div className="travel-opt-dur">{o.dur}</div>
                </div>
                <div className={`radio-circle${selected === i ? " on" : ""}`} />
              </div>
            </div>
          ))}
        </div>

        <div className="mt-6 hidden flex-col gap-4 md:flex">
          <div className="text-xs font-medium uppercase tracking-wide text-gray-500">Recommended for you</div>
          {options.slice(0, 1).map((o, i) => (
            <OptionCard
              key={i}
              Icon={o.CardIcon}
              title={o.name}
              chip={o.chip}
              description={o.sub}
              pricePrimary={o.price}
              priceSecondary={o.dur}
              recommended
              selected={selected === 0}
              onClick={() => setSelected(0)}
            />
          ))}
          <div className="mt-2 text-xs font-medium uppercase tracking-wide text-gray-500">Other options</div>
          <div className="flex flex-col gap-3">
            {options.slice(1).map((o, i) => (
              <OptionCard
                key={o.sub}
                Icon={o.CardIcon}
                title={o.name}
                description={o.sub}
                pricePrimary={o.price}
                priceSecondary={o.dur}
                selected={selected === i + 1}
                onClick={() => setSelected(i + 1)}
              />
            ))}
          </div>
        </div>

        <p className="helper-text mt-2 md:mt-8" style={{ marginTop: 8 }}>You can change this later from the final plan</p>
      </StepLayout>
    </PlannerShell>
  );
};

export default Travel;
